import json

# Load citations
path_citations = locals()['var_function-call-6302261332534400928']
with open(path_citations, 'r') as f:
    citations_data = json.load(f)

# Group by title -> {total, min_year}
title_stats = {}
for entry in citations_data:
    t = entry['title']
    c = int(entry['citation_count'])
    y = int(entry['citation_year'])

    if t not in title_stats:
        title_stats[t] = {'total': 0, 'min_year': 9999}

    title_stats[t]['total'] += c
    if y < title_stats[t]['min_year']:
        title_stats[t]['min_year'] = y

# Load previous results (candidates)
results = locals()['var_function-call-18081898917795127509']
if isinstance(results, str):
    # This shouldn't happen based on previous success, but safe handling
    try:
        with open(results, 'r') as f:
            candidates = json.load(f)
    except:
        candidates = [] # Error
else:
    candidates = results

final_list = []
for item in candidates:
    t = item['title']
    if t in title_stats:
        min_y = title_stats[t]['min_year']
        # We want published > 2016. 
        # If min_citation_year <= 2016, it was likely published <= 2016.
        if min_y > 2016:
            final_list.append(item)
        else:
            # Debug: print excluded
            # print(f"Excluded {t} (Min citation year: {min_y})")
            pass

# Sort
final_list.sort(key=lambda x: x['total_citation_count'], reverse=True)

# Format for output
output_lines = []
for item in final_list:
    output_lines.append(f"Title: {item['title']}, Citations: {item['total_citation_count']}")

print("__RESULT__:")
print(json.dumps(output_lines))

